#include <iostream>
#include <fstream>
#include <string>
using namespace std;
int main() {
    int count = 0;
    string wordToFind = "example"; // replace with the word you want to find
    ifstream file("input.txt"); // replace with the name of your text file
    string line;
    while (getline(file, line)) {
        if (line.find(wordToFind)!= string::npos) {
            count++;
        }
    }
    cout << "The word " << wordToFind << " occurs " << count << " times in the file." << endl;
    return 0;
}
```
This program reads a text file named "input.txt" line by line and counts the number of occurrences of the word "example" in the file. You can replace "example" with the word you want to find. The program stores the count in the variable `count`.
When you run the program, it will output a message with the count of occurrences of the word in the file.

